const input = $input.first().json;
const prev = $('Preparer le prompt').first().json;

// Extraire le contenu de la reponse Claude
let content = '';
if (input.content && input.content[0]) {
  content = input.content[0].text || '';
}

// Nettoyer le contenu (enlever les ```html si present)
content = content.replace(/^```html\n?/, '').replace(/\n?```$/, '').trim();

// Generer le title SEO a partir du keyword
const keyword = prev.keyword;
const titleMap = {
  'default': `${keyword.charAt(0).toUpperCase() + keyword.slice(1)} — Guide complet`
};

const title = titleMap['default'];

// Generer la meta description
const descClean = content.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const description = descClean.substring(0, 150).replace(/\s\S*$/, '') + '...';

// Estimer le temps de lecture
const wordCount = descClean.split(' ').filter(w => w.length > 2).length;
const readMin = Math.max(3, Math.ceil(wordCount / 200));

return {
  title: title,
  slug: prev.slug,
  description: description,
  category: prev.category,
  content: content,
  readTime: `${readMin} min de lecture`
};

const result = $input.first().json;

if (result.success) {
  return {
    status: 'publie',
    url: result.url,
    message: `Article publie avec succes : ${result.url}`
  };
} else {
  return {
    status: 'erreur',
    message: result.message || 'Erreur inconnue'
  };
}
